sql:
SELECT COUNT(*) AS summoner_count
FROM summoners
WHERE rank = 'Platinum' AND tier = 'IV';

SELECT summoner_name
FROM summoners
WHERE rank = 'Platinum' AND tier = 'IV';

SELECT champion_name
FROM champions
WHERE attack_damage = (SELECT MAX(attack_damage) FROM champions);

SELECT champion_name, champion_type
FROM champions
WHERE attack_damage > 50;

external_knowledge:
- Ranked games refer to competitive games as opposed to casual games; 
- Solo ranked games refer to games where players are paired with other solo players, as opposed to flex games where players are paired with their friends; 
- Win percentage is calculated by dividing the total number of wins by the total number of games; 
- Average damage dealt refers to the average amount of damage a player deals to enemy champions, structures, or minions during a game.

sql:
SELECT summoner_name, rank
FROM summoners
ORDER BY rank DESC;

SELECT champion_name, attack_damage
FROM champions
ORDER BY attack_damage DESC;
